const iterations = $.steps.fetchMessages.response.iterations || [];
let emailsWithPdfs = [];

iterations.forEach(iter => {
  const resp = iter.getMessage ? iter.getMessage.response : null;
  if (!resp) return;
  const headers = (resp.payload && resp.payload.headers) || [];
  const subject = (headers.find(h => h.name === 'Subject') || {}).value || '';
  const from = (headers.find(h => h.name === 'From') || {}).value || '';
  const date = (headers.find(h => h.name === 'Date') || {}).value || '';
  const parts = (resp.payload && resp.payload.parts) || [];
  const pdfAttachments = parts.filter(p => p.filename && p.filename.toLowerCase().endsWith('.pdf')).map(p => ({
    filename: p.filename,
    size: p.body ? p.body.size : 0,
    attachmentId: p.body ? p.body.attachmentId : ''
  }));
  if (pdfAttachments.length > 0) {
    emailsWithPdfs.push({ subject, from, date, messageId: resp.id || '', attachments: pdfAttachments });
  }
});

let emailsText = '';
emailsWithPdfs.forEach((e, i) => {
  emailsText += (i + 1) + '. Subject: ' + e.subject + '\n   From: ' + e.from + '\n   PDFs: ' + e.attachments.map(a => a.filename).join(', ') + '\n';
});

return { emailsWithPdfs, emailsText, totalEmails: emailsWithPdfs.length, totalPdfs: emailsWithPdfs.reduce((sum, e) => sum + e.attachments.length, 0) };

const data = $.steps.extractAttachments.output;
const criteria = $.input.filterCriteria;

const prompt = 'You are a document classification specialist. Review these emails with PDF attachments and determine which ones match the target criteria.

TARGET CRITERIA: ' + criteria + '

EMAILS WITH PDFs:
' + data.emailsText + '

Classify each email. Return ONLY valid JSON:
{
  "classifications": [
    {
      "emailNumber": 1,
      "matches": true,
      "confidence": "high/medium/low",
      "reason": "why it matches or doesnt",
      "documentType": "invoice/receipt/contract/report/other"
    }
  ],
  "matchCount": 0,
  "summary": "brief summary of findings"
}';

return { prompt };

let raw = $.steps.aiClassify.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { classifications: [], matchCount: 0, summary: raw.slice(0, 200) }; }

const ai = $.steps.parseAI.output;
const emails = $.steps.extractAttachments.output.emailsWithPdfs || [];
const classifications = ai.classifications || [];
const date = new Date().toISOString().split('T')[0];
const rows = [];

classifications.forEach(c => {
  if (!c.matches) return;
  const email = emails[c.emailNumber - 1];
  if (!email) return;
  email.attachments.forEach(att => {
    rows.push([date, email.from, email.subject, att.filename, Math.round(att.size / 1024) + 'KB', c.documentType || '', c.confidence || '', c.reason || '']);
  });
});

const slackText = 'PDF scan complete: ' + emails.length + ' emails with PDFs found, ' + (ai.matchCount || rows.length) + ' match criteria "' + $.input.filterCriteria + '". ' + (ai.summary || '');
return { rows, slackText };
